const fullText = markdownText.trim();
const finalResults = [];

// 2. 第一层分割
const categoryBlocks = fullText.split(/(?=^##\s)/gm).filter(s => s.trim() !== '');

for (const block of categoryBlocks) {
    let cleanBlock = block.trim();
    let categoryTitle = "Daily Papers";
    let categoryHtml = "";

    const titleMatch = cleanBlock.match(/^##\s*(.+)$/m);
    if (titleMatch) {
        categoryTitle = titleMatch[1].trim();
        categoryHtml = headerTemplate.replace("{{CATEGORY_TITLE}}", categoryTitle);
        cleanBlock = cleanBlock.replace(titleMatch[0], "").trim();
    }

    const firstSplitIndex = cleanBlock.search(/【\d+】/);
    if (firstSplitIndex >= 0) {
        cleanBlock = cleanBlock.substring(firstSplitIndex);
    }

    const paperBlocks = cleanBlock.split(/(?=【\d+】)/g).filter(s => s.trim() !== '');

    let isFirstPaperInCategory = true;

    for (const paperText of paperBlocks) {
        const lines = paperText.split('\n');
        let data = {
            englishTitle: "",
            chineseTitle: "",
            arxivLink: "",
            authors: "",
            notes: "No Notes",
            chineseAbstract: "",
            englishAbstract: ""
        };

        for (const line of lines) {
            const trimmedLine = line.trim();
            if (trimmedLine.startsWith('【')) {
                const bracketIndex = trimmedLine.indexOf('【');
                if (bracketIndex !== -1) {
                    data.englishTitle = trimmedLine.substring(bracketIndex).trim(); 
                } else {
                    data.englishTitle = trimmedLine.trim();
                }
            } else if (trimmedLine.startsWith('- **标题**:')) {
                data.chineseTitle = trimmedLine.substring(trimmedLine.indexOf(':') + 1).trim();
            }else if (trimmedLine.startsWith('- **链接**:')) {
                // 修改说明：直接截取冒号后的内容，移除空格，不再强制要求 [[arxiv](url)] 格式
                data.arxivLink = trimmedLine.substring(trimmedLine.indexOf(':') + 1).trim();
            } else if (trimmedLine.startsWith('> **作者**:')) {
                data.authors = trimmedLine.substring(trimmedLine.indexOf(':') + 1).trim();
            } else if (trimmedLine.startsWith('> **摘要**:')) {
                data.chineseAbstract = trimmedLine.substring(trimmedLine.indexOf(':') + 1).trim();
            } else if (trimmedLine.startsWith('> **Abstract**:')) {
                data.englishAbstract = trimmedLine.substring(trimmedLine.indexOf(':') + 1).trim();
            }
        }

        finalResults.push({
            json: {
                ...data,
                moban: htmlMoban,
                categoryHtml: isFirstPaperInCategory ? categoryHtml : "",
                stats: stats // *** 关键修改：将 stats 传递给每一篇论文 ***
            }
        });

        isFirstPaperInCategory = false; 
    }
}

return finalResults;

