// ================= 配置区域 =================
// 只要标题行中 **包含** 以下任意一个字符串，该版块就会被保留
const targetKeywords = [
    "人机交互(cs.HC:Human-Computer Interaction)",
    "机器人技术(cs.RO:Robotics)",
  "神经元和认知(q-bio.NC:Neurons and Cognition)"
];

// 每个分类最大保留的论文数量
const maxPapersPerCategory = 20; 

// *** 新增：初始化统计对象 ***
const stats = {
    hc: 0,
    ro: 0,
    nc: 0
};
// ===========================================

// 2. 逻辑处理：按 ## 切分所有版块
const blocks = fullText.split(/(?=^##\s)/gm).filter(s => s.trim() !== '');

const filteredBlocks = [];

for (const block of blocks) {
    // 提取当前块的标题行
    const titleMatch = block.match(/^##\s*(.+)$/m);

    if (titleMatch) {
        const currentTitle = titleMatch[1].trim();
        const headerLine = titleMatch[0]; // 获取完整的标题行

        // 检查当前标题是否包含我们的目标关键词
        const isMatch = targetKeywords.some(keyword => currentTitle.includes(keyword));

        if (isMatch) {

            // 1. 去掉标题行，获取剩下的论文内容主体
            let contentBody = block.substring(titleMatch.index + headerLine.length).trim();

            // 2. 按 【数字】 切分论文
            const papers = contentBody.split(/(?=【\d+】)/g).filter(s => s.trim() !== '');

            // *** 新增逻辑：在截取前，统计原始数量 ***
            // 根据标题判断属于哪个分类，并记录数量
            if (currentTitle.includes("cs.HC")) stats.hc = papers.length;
            else if (currentTitle.includes("cs.RO")) stats.ro = papers.length;
            else if (currentTitle.includes("q-bio.NC")) stats.nc = papers.length;

            // 3. 截取前 N 个论文
            const limitedPapers = papers.slice(0, maxPapersPerCategory);

            // 4. 重新组装
            const newBlock = headerLine + "\n\n" + limitedPapers.join("");

            filteredBlocks.push(newBlock);
        }
    }
}

// 3. 合并结果
const resultText = filteredBlocks.join("\n\n");

// 4. 输出
return {
    output: resultText,
    moban: htmlMoban,
    stats: stats // *** 将统计数据传给下一个节点 ***
};

