    });

    // B. 处理 H2 (##)
    markdownText = markdownText.replace(/^##\s(.*?)$/gm, (match, content) => {
        const h2Html = `<h2 id="${headingId++}" style="text-align: center; line-height: 1.75; font-family: ${fontStyle}; font-size: 19.2px; display: table; padding: 0 0.2em; margin: 4em auto 2em; color: #fff; background: ${h1Color}; font-weight: bold" data-heading="true">${content}</h2>`;
