    });

    // C. 处理 H3 (###)
    markdownText = markdownText.replace(/^###\s(.*?)$/gm, (match, content) => {
        const h3Html = `<h3 id="${headingId++}" style="text-align: left; line-height: 1.2; font-family: ${fontStyle}; font-size: 17.6px; padding-left: 8px; border-left: 3px solid ${h1Color}; margin: 2em 8px 0.75em 0; color: #3f3f3f; font-weight: bold" data-heading="true">${content}</h3>`;
        return h3Html;
    });

    // D. 图片
    markdownText = markdownText.replace(/!\[(.*?)\]\((.*?)\)/g, (match, alt, src) => {
        const figureStyle = `text-align: left; line-height: 1.75; font-family: ${fontStyle}; font-size: 16px; margin: 1.5em 8px; color: #3f3f3f`;
        const imgStyle = `text-align: left; line-height: 1.75; font-family: ${fontStyle}; font-size: 16px; display: block; max-width: 100%; margin: 0.1em auto 0.5em; border-radius: 4px`;
        const figcaptionStyle = `text-align: center; line-height: 1.75; font-family: ${fontStyle}; font-size: 0.8em; color: #888`;
        return `<figure style="${figureStyle}"><img alt="${alt}" title="null" src="${src}" style="${imgStyle}"><figcaption style="${figcaptionStyle}">${alt}</figcaption></figure>`;
    });

    // E. 无序列表
    const liStyle = `text-align: left; line-height: 1.75; font-family: ${fontStyle}; font-size: 16px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f`;
    const ulStyle = `text-align: left; line-height: 1.75; font-family: ${fontStyle}; font-size: 16px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f`;
    markdownText = markdownText.replace(/(\n(\s*[\*-]\s.*))+/g, (match) => {
        const lines = match.trim().split('\n').filter(line => line.trim().startsWith('*') || line.trim().startsWith('-'));
        if (lines.length > 0) {
            let ulContent = '';
            for (const line of lines) {
                const content = line.replace(/^\s*[\*-]\s/, '').trim();
                ulContent += `<li style="${liStyle}">• ${content}</li>`;
            }
            return `<ul style="${ulStyle}">${ulContent}</ul>`;
        }
        return match;
    });

    // F. 有序列表
    const olStyle = `text-align: left; line-height: 1.75; font-family: ${fontStyle}; font-size: 16px; padding-left: 1em; margin-left: 0; color: #3f3f3f`;
    markdownText = markdownText.replace(/(\n(\s*\d+\.\s.*))+/g, (match) => {
        const lines = match.trim().split('\n').filter(line => line.trim().match(/^\d+\.\s/));
        if (lines.length > 0) {
            let olContent = '';
            for (const line of lines) {
                const numMatch = line.trim().match(/^(\d+)\.\s/);
                const number = numMatch ? numMatch[1] : '';
                const content = line.replace(/^\s*\d+\.\s/, '').trim();
                olContent += `<li style="${liStyle}">${number}. ${content}</li>`;
            }
            return `<ol style="${olStyle}">${olContent}</ol>`;
        }
        return match;
    });

    // G. 粗体
    const strongStyle = `text-align: left; line-height: 1.75; font-family: ${fontStyle}; font-size: inherit; color: ${h1Color}; font-weight: bold`;
    markdownText = markdownText.replace(/\*\*(.*?)\*\*/g, (match, content) => {
        return `<strong style="${strongStyle}">${content}</strong>`;
    });

    // H. 链接
    markdownText = markdownText.replace(/\[(.*?)\]\((.*?)\)/g, (match, text, url) => url);
    markdownText = markdownText.replace(/<(http|https):\/\/.*?>/g, (match) => match.replace(/<|>/g, ''));

    // I. 段落
    markdownText = markdownText.replace(/\n{2,}/g, 'BLOCK_SEP');
    markdownText = markdownText.replace(/\n/g, ''); 
    markdownText = markdownText.replace(/BLOCK_SEP/g, '\n\n');

    let finalHtml = markdownText.split(/\n{2,}/) 
        .map(block => block.trim())
        .filter(block => block.length > 0)
        .map(block => {
            if (block.startsWith('<h') || block.startsWith('<ul') || block.startsWith('<ol') || block.startsWith('<figure')) {
                return block;
            } else {
                return `<p style="${defaultPStyle}">${block}</p>`;
            }
        })
        .join(''); 

    const finalSection = `<p style="font-size: 0px; line-height: 0; margin: 0px;">&nbsp;</p><section style=" text-align: left; line-height: 1.75; font-family: ${fontStyle}; font-size: 16px">${finalHtml}</section><p style="font-size: 0px; line-height: 0; margin: 0px;">&nbsp;</p>`;

    outputItems.push({
        json: {
            output: finalSection,
            // 关键：将提取到的真实标题传递给下一个节点
            title: realTitle || '璇玑枢学术专递' 
        }
    });
}

return outputItems;

